  1	import { type FC, useCallback, useEffect, useRef } from 'react';
  2	import { FormProvider, useForm } from 'react-hook-form';
  3	import SectionHeading from 'src/components/headers/SectionHeading';
  4	import TabTitle from 'src/overview/components/TabTitle';
  5	import { isPlanEditable } from 'src/plans/details/components/PlanStatus/utils/utils';
  6	import { useForkliftTranslation } from 'src/utils/i18n';
  7	
  8	import LoadingSuspend from '@components/LoadingSuspend';
  9	import { Alert, Flex, FlexItem, PageSection } from '@patternfly/react-core';
 10	
 11	import { usePlan } from '../../hooks/usePlan';
 12	import type { PlanPageProps } from '../../utils/types';
 13	
 14	import HooksCodeEditor from './components/HooksCodeEditor';
 15	import HooksTabActions from './components/HooksTabActions/HooksTabActions';
 16	import { usePlanHooks } from './hooks/usePlanHooks';
 17	import { getDefaultValues } from './state/initialState';
 18	import type { HookFormValues } from './state/types';
 19	import { hookTypes } from './utils/constants';
 20	import { onUpdatePlanHooks } from './utils/utils';
 21	
 22	const PlanHooksPage: FC<PlanPageProps> = ({ name, namespace }) => {
 23	  const { t } = useForkliftTranslation();
 24	  const { plan } = usePlan(name, namespace);
 25	  const isFormInitialized = useRef(false);
 26	
 27	  const { error, loaded, postHookResource, preHookResource, warning } = usePlanHooks(plan);
 28	
 29	  const methods = useForm<HookFormValues>({
 30	    defaultValues: getDefaultValues(postHookResource, preHookResource),
 31	  });
 32	
 33	  const { handleSubmit, reset } = methods;
 34	
 35	  const resetToDefaultValues = useCallback(() => {
 36	    reset(getDefaultValues(postHookResource, preHookResource));
 37	  }, [reset, postHookResource, preHookResource]);
 38	
 39	  // Only reset form on initial load
 40	  useEffect(() => {
 41	    if (loaded && !error && !isFormInitialized.current) {
 42	      resetToDefaultValues();
 43	      isFormInitialized.current = true;
 44	    }
 45	  }, [loaded, error, resetToDefaultValues]);
 46	
 47	  const onSubmit = async (formData: HookFormValues) => {
 48	    await onUpdatePlanHooks({
 49	      formData,
 50	      plan,
 51	      postHookResource: postHookResource!,
 52	      preHookResource: preHookResource!,
 53	    });
 54	
 55	    // Reset the form state to match the new server state
 56	    reset(formData);
 57	  };
 58	
 59	  return (
 60	    <FormProvider {...methods}>
 61	      <LoadingSuspend obj={plan} loaded={loaded} loadError={error}>
 62	        <PageSection variant="light" className="pf-v6-u-h-100">
 63	          <Flex
 64	            direction={{ default: 'column' }}
 65	            justifyContent={{ default: 'justifyContentSpaceBetween' }}
 66	            className="pf-v6-u-h-100"
 67	          >
 68	            <FlexItem>
 69	              <SectionHeading
 70	                text={
 71	                  <TabTitle
 72	                    title={t('Hooks')}
 73	                    helpContent={t(
 74	                      'Hooks are contained in Ansible playbooks that can be run before or after the migration. Hooks are applied to all virtual machines in the plan.',
 75	                    )}
 76	                  />
 77	                }
 78	              />
 79	              {warning && (
 80	                <Alert variant="warning" title={t('The plan hooks were manually configured')}>
 81	                  <p>
 82	                    {t('Warning:')} {warning},
 83	                  </p>
 84	                  <p>{t('updating the hooks will override the current configuration.')}</p>
 85	                </Alert>
 86	              )}
 87	
 88	              <HooksCodeEditor type={hookTypes.PreHook} planEditable={isPlanEditable(plan)} />
 89	              <HooksCodeEditor type={hookTypes.PostHook} planEditable={isPlanEditable(plan)} />
 90	            </FlexItem>
 91	
 92	            <FlexItem>
 93	              <HooksTabActions
 94	                onCancel={resetToDefaultValues}
 95	                onUpdate={handleSubmit(onSubmit)}
 96	                planEditable={isPlanEditable(plan)}
 97	              />
 98	            </FlexItem>
 99	          </Flex>
100	        </PageSection>
101	      </LoadingSuspend>
102	    </FormProvider>
103	  );
104	};
105	
106	export default PlanHooksPage;

